}

const analysis = parseObj(row.analysisJson);
const content = parseObj(row.contentJson);
const visual = parseObj(row.visualJson);

// SourceLock: kanonisch verschachtelt (analysisJson.sourceLock), Fallback auf P3b-Spiegelung (Top-Level row.sourceLock)
const rawSourceLock = (analysis.sourceLock && typeof analysis.sourceLock === 'object') ? analysis.sourceLock : parseObj(row.sourceLock);
const sourceLock = {
  sourceTopic: safeStr(rawSourceLock.sourceTopic),
  sourceConflict: safeStr(rawSourceLock.sourceConflict),
  requiredTerms: asArray(rawSourceLock.requiredTerms),
  requiredObjects: asArray(rawSourceLock.requiredObjects),
  requiredAction: safeStr(rawSourceLock.requiredAction),
  affectedGroups: asArray(rawSourceLock.affectedGroups),
  forbiddenDrift: asArray(rawSourceLock.forbiddenDrift)
};

// VisualAnchors: kanonisch verschachtelt, sonst Fallback auf flache Top-Level-Felder (P3b-Muster)
const rawAnchors = (analysis.visualAnchors && typeof analysis.visualAnchors === 'object') ? analysis.visualAnchors : {
  satireThemaKonkret: row.satireThemaKonkret,
  satireKonfliktKonkret: row.satireKonfliktKonkret,
  visualPflichtobjekte: row.visualPflichtobjekte,
  visualPflichthandlung: row.visualPflichthandlung,
